+export class InPlacePlacer {
+    placeStamp(grid, windowId, stampCols, stampRows, originalPos = null) {
+        const pos = originalPos || {col: 0, row: 0};
+        const col = Math.min(pos.col, grid.cols - stampCols);
+        const row = Math.min(pos.row, grid.rows - stampRows);
+        if (grid.placeWindowAt(windowId, col, row, stampCols, stampRows))
+            return {col, row};
+        return grid.placeWindow(windowId, stampCols, stampRows);
+    }
+}
+
+export class ShelfPlacer {
+    constructor(edge, maxDepth) {
+        this._edge = edge;
+        this._maxDepth = maxDepth;
+        this._currentDepth = 0;
+        this._stamps = [];
+    }
+
+    get reservedDepth() { return this._currentDepth; }
+
+    placeStamp(grid, windowId, stampCols, stampRows) {
+        const isVertical = this._edge === 'left' || this._edge === 'right';
+        if (isVertical)
+            return this._placeVertical(grid, windowId, stampCols, stampRows);
+        else
+            return this._placeHorizontal(grid, windowId, stampCols, stampRows);
+    }
+
+    _placeHorizontal(grid, windowId, stampCols, stampRows) {
+        const isBottom = this._edge === 'bottom';
+        for (let depth = 0; depth < this._maxDepth; depth++) {
+            const row = isBottom
+                ? grid.rows - stampRows - depth
+                : depth;
+            for (let c = 0; c <= grid.cols - stampCols; c++) {
+                if (grid.isAreaFree(c, row, stampCols, stampRows)) {
+                    grid.placeWindowAt(windowId, c, row, stampCols, stampRows);
+                    this._currentDepth = Math.max(this._currentDepth, depth + 1);
+                    this._stamps.push(windowId);
+                    return {col: c, row};
+                }
+            }
+        }
+        return grid.placeWindow(windowId, stampCols, stampRows);
+    }
+
+    _placeVertical(grid, windowId, stampCols, stampRows) {
+        const isRight = this._edge === 'right';
+        for (let depth = 0; depth < this._maxDepth; depth++) {
+            const col = isRight
+                ? grid.cols - stampCols - depth
+                : depth;
+            for (let r = 0; r <= grid.rows - stampRows; r++) {
+                if (grid.isAreaFree(col, r, stampCols, stampRows)) {
+                    grid.placeWindowAt(windowId, col, r, stampCols, stampRows);
+                    this._currentDepth = Math.max(this._currentDepth, depth + 1);
+                    this._stamps.push(windowId);
+                    return {col, row: r};
+                }
+            }
+        }
+        return grid.placeWindow(windowId, stampCols, stampRows);
+    }
+
+    removeStamp(windowId) {
+        const idx = this._stamps.indexOf(windowId);
+        if (idx !== -1) this._stamps.splice(idx, 1);
+        if (this._stamps.length === 0) this._currentDepth = 0;
+    }
+}
+
+export class PackPlacer {
+    placeStamp(grid, windowId, stampCols, stampRows) {
+        return grid.placeWindow(windowId, stampCols, stampRows);
+    }
+
+    repackAll(grid, stamps) {
+        const sorted = [...stamps].sort((a, b) => b.rows - a.rows);
+        const positions = new Map();
+        for (const stamp of sorted) {
+            const pos = grid.placeWindow(stamp.id, stamp.cols, stamp.rows);
+            if (pos) positions.set(stamp.id, pos);
+        }
+        return positions;
+    }
+}

