+#!/usr/bin/env -S gjs -m
+import { describe, it, assertEqual, assertDeepEqual, assertTrue, printResults } from './run.js';
+import { MonitorGrid } from '../lib/gridEngine.js';
+import { InPlacePlacer, ShelfPlacer, PackPlacer } from '../lib/stampPlacer.js';
+
+describe('InPlacePlacer', () => {
+    it('places stamp at the window current position', () => {
+        const grid = new MonitorGrid(1920, 1080, 8, 6);
+        grid.placeWindow('win1', 4, 3);
+        grid.removeWindow('win1');
+        const placer = new InPlacePlacer();
+        const pos = placer.placeStamp(grid, 'win1', 1, 1, {col: 0, row: 0});
+        assertEqual(pos.col, 0);
+        assertEqual(pos.row, 0);
+    });
+});
+
+describe('ShelfPlacer', () => {
+    it('places stamps along bottom edge', () => {
+        const grid = new MonitorGrid(1920, 1080, 8, 6);
+        const placer = new ShelfPlacer('bottom', 2);
+        const pos1 = placer.placeStamp(grid, 'stamp1', 1, 1);
+        assertEqual(pos1.row, 5);
+        assertEqual(pos1.col, 0);
+        const pos2 = placer.placeStamp(grid, 'stamp2', 1, 1);
+        assertEqual(pos2.row, 5);
+        assertEqual(pos2.col, 1);
+    });
+
+    it('wraps to next row when shelf row is full', () => {
+        const grid = new MonitorGrid(1920, 1080, 8, 6);
+        const placer = new ShelfPlacer('bottom', 2);
+        for (let i = 0; i < 8; i++)
+            placer.placeStamp(grid, `stamp${i}`, 1, 1);
+        const pos = placer.placeStamp(grid, 'stamp8', 1, 1);
+        assertEqual(pos.row, 4);
+        assertEqual(pos.col, 0);
+    });
+
+    it('falls back to in-place when shelf is full', () => {
+        const grid = new MonitorGrid(1920, 1080, 4, 4);
+        const placer = new ShelfPlacer('bottom', 2);
+        for (let i = 0; i < 8; i++)
+            placer.placeStamp(grid, `stamp${i}`, 1, 1);
+        const pos = placer.placeStamp(grid, 'stamp8', 1, 1);
+        assertTrue(pos !== null);
+        assertTrue(pos.row < 2);
+    });
+
+    it('returns shelf reserved rows', () => {
+        const placer = new ShelfPlacer('bottom', 2);
+        assertEqual(placer.reservedDepth, 0);
+        placer._currentDepth = 1;
+        assertEqual(placer.reservedDepth, 1);
+    });
+});
+
+describe('PackPlacer', () => {
+    it('packs stamps into free cells, first-fit decreasing height', () => {
+        const grid = new MonitorGrid(1920, 1080, 8, 6);
+        grid.placeWindow('big', 4, 4);
+        const placer = new PackPlacer();
+        const pos = placer.placeStamp(grid, 'stamp1', 2, 2);
+        assertTrue(pos !== null);
+        assertTrue(pos.col >= 4);
+    });
+});
+
+import System from 'system';
+const allPassed = printResults();
+if (!allPassed) System.exit(1);
